noncompliant:
resource vm 'Microsoft.Compute/virtualMachines@2021-07-01' = {
  name: 'exampleVM'
  properties: {
    networkProfile: {
      networkInterfaces: [
        {
          id: '/subscriptions/xxxx/resourceGroups/xxxx/providers/Microsoft.Network/networkInterfaces/exampleNic'
        }
      ]
    }
  }
}

resource nsg 'Microsoft.Network/networkSecurityGroups@2021-02-01' = {
  name: 'exampleNSG'
  properties: {
    securityRules: [
      {
        name: 'Allow-SSH-All'
        properties: {
          protocol: 'Tcp'
          sourcePortRange: '*'
          destinationPortRange: '22'
          sourceAddressPrefix: '*' // Sensitive: allows all IPs
          destinationAddressPrefix: '*'
          access: 'Allow'
          priority: 100
          direction: 'Inbound'
        }
      }
    ]
  }
}

compliant:
resource nsg 'Microsoft.Network/networkSecurityGroups@2021-02-01' = {
  name: 'exampleNSG'
  properties: {
    securityRules: [
      {
        name: 'Allow-SSH-Admin'
        properties: {
          protocol: 'Tcp'
          sourcePortRange: '*'
          destinationPortRange: '22'
          sourceAddressPrefix: '203.0.113.10' // Only admin IP
          destinationAddressPrefix: '*'
          access: 'Allow'
          priority: 100
          direction: 'Inbound'
        }
      }
    ]
  }
}
